public ImmutableSet<ClassInfo> getTopLevelClasses() {
    return FluentIterable.from(resources)
        .filter(ClassInfo.class)
        .filter(
            new Predicate<ClassInfo>() {
              @Override
              public boolean apply(ClassInfo info) {
                return info.isTopLevel();
              }
            })
        .toSet();
  }
